package dashboard

import (
	"fmt"
	"sort"
	"strings"
	"time"

	"github.com/charmbracelet/lipgloss"

	"github.com/jcleira/entire-local/pkg/checkpoint"
)

func renderOverview(stats checkpoint.OverviewStats, width int) string {
	cardWidth := (width - 10) / 4
	if cardWidth < 18 {
		cardWidth = 18
	}
	if cardWidth > 40 {
		cardWidth = 40
	}

	cards := []string{
		renderStatCardDynamic("Checkpoints", fmt.Sprintf("%d", stats.TotalCheckpoints), "total", cardWidth),
		renderStatCardDynamic("Avg Tokens", fmt.Sprintf("%d", stats.AvgTokens), "per checkpoint", cardWidth),
		renderStatCardDynamic("Peak Duration", stats.PeakDuration, "longest session", cardWidth),
		renderStatCardDynamic("Streak", fmt.Sprintf("%d days", stats.StreakDays), "consecutive", cardWidth),
	}

	cardRow := lipgloss.JoinHorizontal(lipgloss.Top, cards...)

	chart := renderActivityChart(stats.ActivityByDay, width)

	return lipgloss.JoinVertical(lipgloss.Left,
		headerStyle.Render("Overview"),
		"",
		cardRow,
		"",
		chart,
	)
}

func renderStatCardDynamic(label, value, sub string, cardWidth int) string {
	content := lipgloss.JoinVertical(lipgloss.Left,
		statValueStyle.Render(value),
		statLabelStyle.Render(label),
		dimStyle.Render(sub),
	)
	return statCardStyle.Width(cardWidth).Render(content)
}

func renderActivityChart(activity map[string]int, width int) string {
	if len(activity) == 0 {
		return dimStyle.Render("  No activity data")
	}

	days := last30Days()
	maxCount := 0
	for _, d := range days {
		if c := activity[d]; c > maxCount {
			maxCount = c
		}
	}
	if maxCount == 0 {
		maxCount = 1
	}

	blocks := []rune{'░', '▒', '▓', '█'}
	barWidth := width - 16
	if barWidth < 10 {
		barWidth = 10
	}

	var sb strings.Builder
	sb.WriteString(dimStyle.Render("  Activity (last 30 days)"))
	sb.WriteString("\n  ")

	shown := barWidth
	if shown > len(days) {
		shown = len(days)
	}
	start := len(days) - shown

	for i := start; i < len(days); i++ {
		count := activity[days[i]]
		if count == 0 {
			sb.WriteString(dimStyle.Render("·"))
		} else {
			idx := (count * len(blocks) / (maxCount + 1))
			if idx >= len(blocks) {
				idx = len(blocks) - 1
			}
			sb.WriteString(lipgloss.NewStyle().Foreground(primary).Render(string(blocks[idx])))
		}
	}

	return sb.String()
}

func last30Days() []string {
	days := make([]string, 30)
	now := time.Now()
	for i := range 30 {
		days[i] = now.AddDate(0, 0, -(29 - i)).Format("2006-01-02")
	}
	sort.Strings(days)
	return days
}

package dashboard

import (
	"fmt"
	"strings"

	"github.com/charmbracelet/bubbles/key"
	tea "github.com/charmbracelet/bubbletea"
	"github.com/charmbracelet/lipgloss"

	"github.com/jcleira/entire-local/pkg/checkpoint"
)

type model struct {
	loader     *checkpoint.Loader
	summaries  []checkpoint.CheckpointSummary
	stats      checkpoint.OverviewStats
	detail     *checkpoint.Checkpoint
	transcript []checkpoint.TranscriptEntry

	screen       screen
	cursor       int
	width        int
	height       int
	filter       string
	filtering    bool
	showHelp     bool
	err          error
	detailTab    detailTab
	scrollOffset int
	maxScroll    int
}

func RunDashboard(loader *checkpoint.Loader) error {
	m := model{
		loader: loader,
		screen: screenOverview,
		width:  80,
		height: 24,
	}

	p := tea.NewProgram(m, tea.WithAltScreen())
	_, err := p.Run()
	return err
}

func (m model) Init() tea.Cmd {
	return m.loadCheckpoints()
}

func (m model) Update(msg tea.Msg) (tea.Model, tea.Cmd) {
	switch msg := msg.(type) {
	case tea.WindowSizeMsg:
		m.width = msg.Width
		m.height = msg.Height
		return m, nil

	case tea.KeyMsg:
		if m.filtering {
			return m.handleFilterInput(msg)
		}
		return m.handleKeyPress(msg)

	case checkpointsLoadedMsg:
		m.summaries = msg.summaries
		m.stats = checkpoint.ComputeStats(msg.summaries)
		return m, nil

	case checkpointDetailLoadedMsg:
		m.detail = msg.checkpoint
		return m, nil

	case transcriptLoadedMsg:
		m.transcript = msg.entries
		return m, nil

	case errMsg:
		m.err = msg.err
		return m, nil
	}

	return m, nil
}

func (m model) View() string {
	if m.showHelp {
		return renderHelp(m.width, m.height)
	}

	if m.err != nil {
		return lipgloss.Place(m.width, m.height,
			lipgloss.Center, lipgloss.Center,
			lipgloss.NewStyle().Foreground(errClr).Render("Error: "+m.err.Error()),
		)
	}

	var content string

	switch m.screen {
	case screenOverview:
		overview := renderOverview(m.stats, m.width)
		overviewLines := strings.Count(overview, "\n") + 1
		listHeight := m.height - overviewLines - 3
		if listHeight < 5 {
			listHeight = 5
		}
		list := renderCheckpointList(m.summaries, m.cursor, listHeight, m.filter, m.width)
		content = lipgloss.JoinVertical(lipgloss.Left, overview, "", list)

	case screenDetail:
		content = renderCheckpointDetail(m.detail, m.transcript, m.width, m.height-2, m.detailTab, m.scrollOffset)
	}

	footer := m.renderFooter()

	return lipgloss.JoinVertical(lipgloss.Left,
		content,
		footer,
	)
}

func (m model) handleKeyPress(msg tea.KeyMsg) (tea.Model, tea.Cmd) {
	switch {
	case key.Matches(msg, keys.Quit):
		return m, tea.Quit

	case key.Matches(msg, keys.Help):
		m.showHelp = !m.showHelp
		return m, nil

	case key.Matches(msg, keys.Refresh):
		return m, m.loadCheckpoints()

	case key.Matches(msg, keys.Filter):
		if m.screen == screenOverview {
			m.filtering = true
			return m, nil
		}
	}

	switch m.screen {
	case screenOverview:
		return m.handleOverviewKeys(msg)
	case screenDetail:
		return m.handleDetailKeys(msg)
	}

	return m, nil
}

func (m model) handleOverviewKeys(msg tea.KeyMsg) (tea.Model, tea.Cmd) {
	filtered := filterSummaries(m.summaries, m.filter)

	switch {
	case key.Matches(msg, keys.Down):
		if m.cursor < len(filtered)-1 {
			m.cursor++
		}

	case key.Matches(msg, keys.Up):
		if m.cursor > 0 {
			m.cursor--
		}

	case key.Matches(msg, keys.Enter):
		if len(filtered) > 0 && m.cursor < len(filtered) {
			selected := filtered[m.cursor]
			m.screen = screenDetail
			m.detail = nil
			m.transcript = nil
			m.detailTab = tabOverview
			m.scrollOffset = 0
			return m, tea.Batch(
				m.loadDetail(selected.ID),
				m.loadTranscript(selected.ID),
			)
		}
	}

	return m, nil
}

func (m model) handleDetailKeys(msg tea.KeyMsg) (tea.Model, tea.Cmd) {
	switch {
	case key.Matches(msg, keys.Back):
		m.screen = screenOverview
		m.detail = nil
		m.transcript = nil
		m.scrollOffset = 0
		return m, nil

	case key.Matches(msg, keys.Tab):
		m.detailTab = (m.detailTab + 1) % 4
		m.scrollOffset = 0
		return m, nil

	case key.Matches(msg, keys.ShiftTab):
		m.detailTab = (m.detailTab + 3) % 4
		m.scrollOffset = 0
		return m, nil

	case key.Matches(msg, keys.Num1):
		m.detailTab = tabOverview
		m.scrollOffset = 0
		return m, nil

	case key.Matches(msg, keys.Num2):
		m.detailTab = tabFiles
		m.scrollOffset = 0
		return m, nil

	case key.Matches(msg, keys.Num3):
		m.detailTab = tabTranscript
		m.scrollOffset = 0
		return m, nil

	case key.Matches(msg, keys.Num4):
		m.detailTab = tabPlan
		m.scrollOffset = 0
		return m, nil

	case key.Matches(msg, keys.Down):
		if m.scrollOffset < m.maxScroll {
			m.scrollOffset++
		}
		return m, nil

	case key.Matches(msg, keys.Up):
		if m.scrollOffset > 0 {
			m.scrollOffset--
		}
		return m, nil
	}

	return m, nil
}

func (m model) handleFilterInput(msg tea.KeyMsg) (tea.Model, tea.Cmd) {
	switch msg.Type {
	case tea.KeyEnter, tea.KeyEscape:
		m.filtering = false
		if msg.Type == tea.KeyEscape {
			m.filter = ""
		}
		m.cursor = 0
		return m, nil
	case tea.KeyBackspace:
		if m.filter != "" {
			m.filter = m.filter[:len(m.filter)-1]
		}
		m.cursor = 0
		return m, nil
	default:
		if len(msg.Runes) > 0 {
			m.filter += string(msg.Runes)
			m.cursor = 0
		}
		return m, nil
	}
}

func (m model) renderFooter() string {
	if m.filtering {
		return footerStyle.Render(fmt.Sprintf("Filter: %s█", m.filter))
	}

	var parts []string
	switch m.screen {
	case screenOverview:
		parts = append(parts, dimStyle.Render("j/k navigate  enter select  / filter  ? help  q quit"))
	case screenDetail:
		parts = append(parts, dimStyle.Render("esc back  j/k scroll  tab switch  1-4 tabs  ? help  q quit"))
	}

	return footerStyle.Render(strings.Join(parts, "  "))
}

func (m model) loadCheckpoints() tea.Cmd {
	return func() tea.Msg {
		summaries, err := m.loader.ListCheckpoints()
		if err != nil {
			return errMsg{err}
		}
		return checkpointsLoadedMsg{summaries}
	}
}

func (m model) loadDetail(id string) tea.Cmd {
	return func() tea.Msg {
		cp, err := m.loader.LoadCheckpoint(id)
		if err != nil {
			return errMsg{err}
		}
		return checkpointDetailLoadedMsg{cp}
	}
}

func (m model) loadTranscript(id string) tea.Cmd {
	return func() tea.Msg {
		entries, err := m.loader.LoadTranscript(id)
		if err != nil {
			return errMsg{err}
		}
		return transcriptLoadedMsg{entries}
	}
}

package dashboard

import "github.com/jcleira/entire-local/pkg/checkpoint"

type screen int

const (
	screenOverview screen = iota
	screenDetail
)

type detailTab int

const (
	tabOverview detailTab = iota
	tabFiles
	tabTranscript
	tabPlan
)

type checkpointsLoadedMsg struct {
	summaries []checkpoint.CheckpointSummary
}

type checkpointDetailLoadedMsg struct {
	checkpoint *checkpoint.Checkpoint
}

type transcriptLoadedMsg struct {
	entries []checkpoint.TranscriptEntry
}

type errMsg struct {
	err error
}

