import (
	"fmt"
	"strings"

	"github.com/charmbracelet/lipgloss"

	"github.com/jcleira/entire-local/pkg/checkpoint"
)

func renderCheckpointDetail(cp *checkpoint.Checkpoint, transcript []checkpoint.TranscriptEntry, width, height int, tab detailTab, scrollOffset int) string {
	if cp == nil {
		return dimStyle.Render("Loading checkpoint...")
	}

	tabBar := renderTabBar(tab)
	header := renderDetailHeader(cp, width)

	contentHeight := height - strings.Count(header, "\n") - 4
	if contentHeight < 3 {
		contentHeight = 3
	}

	var tabContent string
	switch tab {
	case tabOverview:
		tabContent = renderTabOverview(cp, width, contentHeight)
	case tabFiles:
		tabContent = renderTabFiles(cp.Diff, width, contentHeight)
	case tabTranscript:
		tabContent = renderTabTranscript(transcript, width, contentHeight, scrollOffset)
	case tabPlan:
		tabContent = renderTabPlan(cp.Plan, width, contentHeight)
	}

	lines := strings.Split(tabContent, "\n")
	if tab != tabTranscript {
		maxScroll := len(lines) - contentHeight
		if maxScroll < 0 {
			maxScroll = 0
		}
		if scrollOffset > maxScroll {
			scrollOffset = maxScroll
		}
		end := scrollOffset + contentHeight
		if end > len(lines) {
			end = len(lines)
		}
		if scrollOffset < len(lines) {
			tabContent = strings.Join(lines[scrollOffset:end], "\n")
		}
	}

	return lipgloss.JoinVertical(lipgloss.Left, header, tabBar, "", tabContent)
}

func renderTabBar(active detailTab) string {
	tabs := []struct {
		label string
		tab   detailTab
	}{
		{"Overview", tabOverview},
		{"Files", tabFiles},
		{"Transcript", tabTranscript},
		{"Plan", tabPlan},
	}

	var parts []string
	for _, t := range tabs {
		if t.tab == active {
			parts = append(parts, tabActiveStyle.Render(" ["+t.label+"] "))
		} else {
			parts = append(parts, tabInactiveStyle.Render("  "+t.label+"  "))
		}
	}

	return "  " + strings.Join(parts, "")
}

func renderDetailHeader(cp *checkpoint.Checkpoint, _ int) string {
	parts := make([]string, 0, 2)

	parts = append(parts, headerStyle.Render("Checkpoint Detail"))

	row1 := fmt.Sprintf(
		"%s  %s  %s",
		hashStyle.Render("commit "+truncateHash(cp.CommitHash)),
		branchStyle.Render(cp.Branch),
		agentBadgeStyle.Render(fmt.Sprintf("%s %d%%", cp.Agent, cp.AgentPercent)),
	)

	var metaParts []string
	if cp.Session.TotalTokens > 0 {
		metaParts = append(metaParts, dimStyle.Render(fmt.Sprintf("tokens: %s", formatNumber(cp.Session.TotalTokens))))
	}
	if cp.Session.Duration != "" {
		metaParts = append(metaParts, dimStyle.Render(fmt.Sprintf("duration: %s", cp.Session.Duration)))
	}

	diffStats := parseDiffStats(cp.Diff)
	if diffStats.totalAdd > 0 || diffStats.totalDel > 0 {
		metaParts = append(metaParts,
			addStyle.Render(fmt.Sprintf("+%d", diffStats.totalAdd))+" "+
				delStyle.Render(fmt.Sprintf("-%d", diffStats.totalDel))+" "+
				dimStyle.Render(fmt.Sprintf("%d files", len(diffStats.files))))
	}

	if len(metaParts) > 0 {
		row1 += "  " + strings.Join(metaParts, "  ")
	}

	parts = append(parts, "  "+row1)

	return strings.Join(parts, "\n")
}

func renderTabOverview(cp *checkpoint.Checkpoint, width, _ int) string {
	var sb strings.Builder
	contentWidth := width - 6
	if contentWidth < 30 {
		contentWidth = 30
	}

	if cp.Prompt != "" {
		sb.WriteString(sectionHeaderStyle.Render("  Prompt"))
		sb.WriteString("\n")
		promptBox := panelStyle.Width(contentWidth).Render(wordWrap(cp.Prompt, contentWidth-4))
		sb.WriteString("  " + promptBox)
		sb.WriteString("\n\n")
	}

	if cp.Context != "" {
		sb.WriteString(sectionHeaderStyle.Render("  Context"))
		sb.WriteString("\n")
		ctx := wordWrap(cp.Context, contentWidth)
		sb.WriteString("  " + contextStyle.Render(ctx))
		sb.WriteString("\n\n")
	}

	if cp.Plan != "" {
		sb.WriteString(sectionHeaderStyle.Render("  Plan Preview"))
		sb.WriteString("\n")
		planLines := strings.Split(cp.Plan, "\n")
		shown := 10
		if shown > len(planLines) {
			shown = len(planLines)
		}
		for i := range shown {
			line := planLines[i]
			if len(line) > contentWidth {
				line = line[:contentWidth-1] + "…"
			}
			sb.WriteString("  " + dimStyle.Render(line) + "\n")
		}
		if len(planLines) > shown {
			sb.WriteString(dimStyle.Render(fmt.Sprintf("  ... +%d more lines (press 4 for full plan)", len(planLines)-shown)))
		}
	}

	if sb.Len() == 0 {
		sb.WriteString(dimStyle.Render("  No overview data available"))
	}

	return sb.String()
}

type fileDiffStat struct {
	name string
	add  int
	del  int
}

type diffStatsResult struct {
	files    []fileDiffStat
	totalAdd int
	totalDel int
}

func parseDiffStats(diff string) diffStatsResult {
	var result diffStatsResult
	if diff == "" {
		return result
	}

	var current *fileDiffStat
	for _, line := range strings.Split(diff, "\n") {
		if strings.HasPrefix(line, "diff --git") {
			if current != nil {
				result.files = append(result.files, *current)
			}
			parts := strings.Fields(line)
			name := ""
			if len(parts) >= 4 {
				name = strings.TrimPrefix(parts[3], "b/")
			}
			current = &fileDiffStat{name: name}
		} else if current != nil {
			if strings.HasPrefix(line, "+") && !strings.HasPrefix(line, "+++") {
				current.add++
			} else if strings.HasPrefix(line, "-") && !strings.HasPrefix(line, "---") {
				current.del++
			}
		}
	}
	if current != nil {
		result.files = append(result.files, *current)
	}

	for _, f := range result.files {
		result.totalAdd += f.add
		result.totalDel += f.del
	}

	return result
}

func renderTabFiles(diff string, width, _ int) string {
	stats := parseDiffStats(diff)

	if len(stats.files) == 0 {
		return dimStyle.Render("  No files changed")
	}

	var sb strings.Builder

	headerLine := fmt.Sprintf("  Files (%d)", len(stats.files))
	totalStat := addStyle.Render(fmt.Sprintf("+%d", stats.totalAdd)) + " " +
		delStyle.Render(fmt.Sprintf("-%d", stats.totalDel)) + dimStyle.Render(" total")
	padding := width - lipgloss.Width(headerLine) - lipgloss.Width(totalStat) - 4
	if padding < 2 {
		padding = 2
	}
	sb.WriteString(sectionHeaderStyle.Render(headerLine) + strings.Repeat(" ", padding) + totalStat)
	sb.WriteString("\n")

	nameWidth := width - 24
	if nameWidth < 20 {
		nameWidth = 20
	}

	for _, f := range stats.files {
		name := f.name
		if len(name) > nameWidth {
			name = "…" + name[len(name)-nameWidth+1:]
		}

		fileStat := addStyle.Render(fmt.Sprintf("+%d", f.add)) + " " +
			delStyle.Render(fmt.Sprintf("-%d", f.del))
		pad := width - len(name) - lipgloss.Width(fileStat) - 8
		if pad < 2 {
			pad = 2
		}
		sb.WriteString("    " + name + strings.Repeat(" ", pad) + fileStat + "\n")
	}

	return sb.String()
}

func renderTabPlan(plan string, width, _ int) string {
	if plan == "" {
		return dimStyle.Render("  No plan available")
	}

	contentWidth := width - 6
	if contentWidth < 30 {
		contentWidth = 30
	}

	var sb strings.Builder
	sb.WriteString(sectionHeaderStyle.Render("  Plan"))
	sb.WriteString("\n\n")

	wrapped := wordWrap(plan, contentWidth)
	for _, line := range strings.Split(wrapped, "\n") {
		sb.WriteString("  " + line + "\n")
	}

	return sb.String()
}

func wordWrap(text string, width int) string {
	if width <= 0 {
		return text
	}
	var result strings.Builder
	for _, line := range strings.Split(text, "\n") {
		if len(line) <= width {
			result.WriteString(line + "\n")
			continue
		}
		remaining := line
		for len(remaining) > width {
			breakAt := width
			if idx := strings.LastIndex(remaining[:width], " "); idx > 0 {
				breakAt = idx
			}
			result.WriteString(remaining[:breakAt] + "\n")
			remaining = strings.TrimLeft(remaining[breakAt:], " ")
		}
		if remaining != "" {
			result.WriteString(remaining + "\n")
		}
	}
	return strings.TrimRight(result.String(), "\n")
}

